DELETE FROM "ClientJob" WHERE "clientId" = 'cl27d7c19cf5525842f021b6e';

-- Daily revenue aggregates for Jan 1 - Feb 22

-- Detailed jobs for weeks 9-14 (with lead sources)

SELECT count(*) as total, round(sum(total)::numeric, 2) as revenue FROM "ClientJob" WHERE "clientId" = 'cl27d7c19cf5525842f021b6e';
SELECT "leadSource", count(*), round(sum(total)::numeric, 2) as revenue FROM "ClientJob" WHERE "clientId" = 'cl27d7c19cf5525842f021b6e' AND "leadSource" IS NOT NULL GROUP BY "leadSource" ORDER BY revenue DESC;